public void testContainsAnyCharArrayWithMixedSupplementaryAndBMP() {
	// Test mixing BMP and supplementary characters
	assertEquals(true, StringUtils.containsAny("abc" + CharU20000, new char[]{'a'}));
	assertEquals(true, StringUtils.containsAny("abc" + CharU20000, new char[]{'c'}));
	assertEquals(false, StringUtils.containsAny("abc", CharU20000.toCharArray()));
	assertEquals(false, StringUtils.containsAny(CharU20000, new char[]{'a', 'b', 'c'}));
}

public void testContainsAnyCharArrayWithLoneSurrogates() {
	// Test with lone surrogates (not paired)
	char highSurrogate = CharU20000.charAt(0);
	char lowSurrogate = CharU20000.charAt(1);
	// Search with just high surrogate should match if cs contains that high surrogate
	assertEquals(true, StringUtils.containsAny(CharU20000, new char[]{highSurrogate}));
	// Search with just low surrogate should match if cs contains that low surrogate  
	assertEquals(true, StringUtils.containsAny(CharU20000, new char[]{lowSurrogate}));
	// But mismatched surrogate pairs should not match the supplementary character
	char highSurrogate2 = CharU20001.charAt(0);
	char lowSurrogate2 = CharU20001.charAt(1);
	assertEquals(false, StringUtils.containsAny(CharU20000, new char[]{highSurrogate, lowSurrogate2}));
	assertEquals(false, StringUtils.containsAny(CharU20000, new char[]{highSurrogate2, lowSurrogate}));
}

public void testContainsAnyCharArrayEdgeCases() {
	// Test empty and null cases are still handled correctly
	assertEquals(false, StringUtils.containsAny("", new char[]{'a'}));
	assertEquals(false, StringUtils.containsAny("a", new char[]{}));
	// Test single BMP character
	assertEquals(true, StringUtils.containsAny("a", new char[]{'a'}));
	assertEquals(false, StringUtils.containsAny("a", new char[]{'b'}));
	// Test supplementary at different positions
	assertEquals(true, StringUtils.containsAny(CharU20000 + "abc", CharU20000.toCharArray()));
	assertEquals(true, StringUtils.containsAny("abc" + CharU20000, CharU20000.toCharArray()));
	assertEquals(true, StringUtils.containsAny("a" + CharU20000 + "c", CharU20000.toCharArray()));
}
